record.field:
{
    "type": "object",
    "properties": {
        "model": {"type": "string", "description": "Technical model name (e.g., 'res.partner', 'sale.order')"},
        "domain": {"type": "array", "description": "Odoo domain filter (e.g., [['is_company','=',true]])", "default": []},
        "fields": {"type": "array", "items": {"type": "string"}, "description": "Fields to return. Empty = smart defaults (excludes binary/metadata)."},
        "limit": {"type": "integer", "description": "Max records to return (default 10, max configurable)", "default": 10},
        "offset": {"type": "integer", "description": "Number of records to skip for pagination", "default": 0},
        "order": {"type": "string", "description": "Sort order (e.g., 'name asc, id desc')"},
        "context": {"type": "object", "description": "Optional ORM context dict. Use 'lang' for language (e.g. 'en_US'), 'tz' for timezone, 'allowed_company_ids' for multi-company operations (e.g. [1]). Example: {\"lang\": \"en_US\", \"allowed_company_ids\": [1]}"}
    },
    "required": ["model"]
}

