{
    "type": "object",
    "properties": {
        "model": {"type": "string", "description": "Technical model name (e.g., 'sale.order', 'account.move')"},
        "groupby": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Fields to group by. Date fields support granularity suffix: 'date_order:month', 'invoice_date:year'. Many2one fields group by related record."
        },
        "fields": {
            "type": "array",
            "items": {"type": "string"},
            "description": "Aggregate expressions: 'field' (default agg), 'field:sum', 'field:avg', 'field:min', 'field:max', 'field:count_distinct'. Empty = only __count per group.",
            "default": []
        },
        "domain": {"type": "array", "description": "Odoo domain filter to limit records before grouping", "default": []},
        "limit": {"type": "integer", "description": "Max number of groups to return"},
        "offset": {"type": "integer", "description": "Number of groups to skip", "default": 0},
        "orderby": {"type": "string", "description": "Sort order for groups (e.g., 'amount_total:sum desc')"},
        "lazy": {"type": "boolean", "description": "If true, group only by first groupby field; remaining go into __context. Default false (all groupby applied at once).", "default": false},
        "context": {"type": "object", "description": "Optional ORM context dict (lang, tz, allowed_company_ids)"}
    },
    "required": ["model", "groupby"]
}

{
    "type": "object",
    "properties": {
        "model": {"type": "string", "description": "Technical model name"},
        "fields": {"type": "array", "items": {"type": "string"}, "description": "Fields to get defaults for. Empty = all fields."},
        "context": {"type": "object", "description": "Optional ORM context dict. Use 'lang' for language (e.g. 'en_US'), 'tz' for timezone, 'allowed_company_ids' for multi-company operations (e.g. [1]). Example: {\"lang\": \"en_US\", \"allowed_company_ids\": [1]}"}
    },
    "required": ["model"]
}

