        "kwargs": {"type": "object", "description": "Keyword arguments", "default": {}},
        "context": {"type": "object", "description": "Optional ORM context dict. Use 'lang' for language (e.g. 'en_US'), 'tz' for timezone, 'allowed_company_ids' for multi-company operations (e.g. [1]). Example: {\"lang\": \"en_US\", \"allowed_company_ids\": [1]}"}
    },
    "required": ["model", "method"]
}
